SELECT grouping(mp_dual.event_month) * $1 + grouping(mp_dual.lag_day) * $2 + grouping(mp_dual.delta_day) * $3 AS grouping_id, mp_dual.event_month AS event_month, mp_dual.lag_day AS lag_day, mp_dual.delta_day AS delta_day, count(*) AS row_count, coalesce(sum(mp_dual.is_source_eligible), $4) AS n_source_eligible, coalesce(sum(mp_dual.is_null_event_time), $5) AS n_null_event_time, coalesce(sum(mp_dual.is_null_source_only), $6) AS n_null_source_only, coalesce(sum(mp_dual.is_negative_clipped), $7) AS n_negative_clipped, coalesce(sum(mp_dual.is_negative_lag_excluded), $8) AS n_negative_lag_excluded, coalesce(sum(mp_dual.is_overflow), $9) AS n_overflow, coalesce(sum(mp_dual.is_delta_row), $10) AS n_delta_rows, max(mp_dual.lookup_dup) AS max_lookup_dup 
FROM mp_dual GROUP BY GROUPING SETS ((mp_dual.event_month, mp_dual.lag_day), (mp_dual.delta_day), ()) 
 LIMIT $11
